import React, { useState, useEffect, useRef, useCallback } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import L from 'leaflet';
import { useAuth } from '../App';
import api from '../api';
import { analyzeSymptoms } from '../engine/analyzer.js';

// Fix leaflet default icons
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl:       'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl:     'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

const I = ({ c, style }) => <i className={`fa-solid ${c}`} style={style} />;

// ── Map fly-to helper ─────────────────────────────────────────────────────────
function FlyTo({ coords }) {
  const map = useMap();
  useEffect(() => { if (coords) map.flyTo(coords, 13, { duration: 1.2 }); }, [coords, map]);
  return null;
}

// ── Deficiency Result Card ────────────────────────────────────────────────────
const DEF_ICONS = {
  iron:'fa-droplet', vitamin_a:'fa-eye', vitamin_d:'fa-sun', vitamin_b12:'fa-brain',
  folate:'fa-seedling', iodine:'fa-shield-halved', zinc:'fa-shield', calcium:'fa-bone',
  vitamin_c:'fa-lemon', protein:'fa-dumbbell',
};

function DefCard({ r }) {
  const [open, setOpen] = useState(false);
  const iconClass = DEF_ICONS[r.id] || 'fa-circle-dot';
  return (
    <div style={{ background:'#fff', border:`1.5px solid ${r.color}30`, borderRadius:12, overflow:'hidden', marginBottom:10 }}>
      <div style={{ padding:'1rem' }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', flexWrap:'wrap', gap:8 }}>
          <div style={{ display:'flex', alignItems:'center', gap:10 }}>
            <div style={{ width:38, height:38, borderRadius:10, background:r.bg, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
              <I c={iconClass} style={{ color:r.color, fontSize:'1.1rem' }}/>
            </div>
            <div>
              <div style={{ fontWeight:700, fontSize:'0.95rem', color:r.color }}>{r.name}</div>
              <div style={{ fontSize:'0.72rem', color:'#6b7280' }}>ICD {r.icd} · {r.severity}</div>
            </div>
          </div>
          <div style={{ display:'flex', alignItems:'center', gap:8 }}>
            <span style={{ background:r.color, color:'white', borderRadius:20, padding:'3px 10px', fontSize:'0.75rem', fontWeight:700 }}>{r.confidence}% match</span>
            <button onClick={()=>setOpen(!open)} style={{ background:'none', border:`1px solid ${r.color}40`, borderRadius:8, color:r.color, cursor:'pointer', padding:'4px 10px', fontSize:'0.75rem', fontWeight:600 }}>
              {open ? <><I c="fa-chevron-up" style={{marginRight:4}}/>Less</> : <><I c="fa-chevron-down" style={{marginRight:4}}/>Details</>}
            </button>
          </div>
        </div>

        <div style={{ marginTop:8, fontSize:'0.78rem', color:'#6b7280', background:'#f9fafb', borderRadius:8, padding:'6px 10px' }}>
          <I c="fa-location-dot" style={{marginRight:5, color:'#16a34a'}}/>{r.kenya_stat}
        </div>

        {r.matched_symptoms?.length > 0 && (
          <div style={{ marginTop:8, display:'flex', flexWrap:'wrap', gap:5 }}>
            {r.matched_symptoms.map(s => (
              <span key={s} style={{ background:`${r.color}12`, color:r.color, border:`1px solid ${r.color}30`, borderRadius:12, padding:'2px 8px', fontSize:'0.7rem', fontWeight:600 }}>
                <I c="fa-check" style={{marginRight:4}}/>{s}
              </span>
            ))}
          </div>
        )}
      </div>

      {open && (
        <div style={{ padding:'1rem', background:'#fafafa', borderTop:`1px solid ${r.color}15` }}>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12 }}>
            <div>
              <div style={{ fontSize:'0.72rem', fontWeight:700, color:'#16a34a', textTransform:'uppercase', marginBottom:6 }}>
                <I c="fa-leaf" style={{marginRight:5}}/>Kenyan Foods
              </div>
              <ul style={{ paddingLeft:16, fontSize:'0.82rem', lineHeight:1.9, color:'#374151' }}>
                {r.foods_recommended.map(f => <li key={f}>{f}</li>)}
              </ul>
            </div>
            <div>
              <div style={{ fontSize:'0.72rem', fontWeight:700, color:'#d97706', textTransform:'uppercase', marginBottom:6 }}>
                <I c="fa-lightbulb" style={{marginRight:5}}/>Tips
              </div>
              <ul style={{ paddingLeft:16, fontSize:'0.82rem', lineHeight:1.9, color:'#374151' }}>
                {r.tips.map(t => <li key={t}>{t}</li>)}
              </ul>
              {r.foods_avoid?.length > 0 && (
                <>
                  <div style={{ fontSize:'0.72rem', fontWeight:700, color:'#dc2626', textTransform:'uppercase', margin:'10px 0 4px' }}>
                    <I c="fa-ban" style={{marginRight:5}}/>Limit / Avoid
                  </div>
                  <ul style={{ paddingLeft:16, fontSize:'0.82rem', lineHeight:1.9, color:'#dc2626' }}>
                    {r.foods_avoid.map(f => <li key={f}>{f}</li>)}
                  </ul>
                </>
              )}
            </div>
          </div>
          <div style={{ marginTop:10, background:'#fff', border:'1px solid #e5e7eb', borderRadius:8, padding:'8px 12px', fontSize:'0.8rem' }}>
            <I c="fa-capsules" style={{marginRight:6, color:'#6b7280'}}/><strong>Supplement:</strong> {r.supplement}
          </div>
          <div style={{ marginTop:8, background:'#fef2f2', border:'1px solid #fca5a5', borderRadius:8, padding:'8px 12px', fontSize:'0.78rem', color:'#dc2626' }}>
            <I c="fa-hospital" style={{marginRight:6}}/><strong>See a doctor if:</strong> {r.when_to_see_doctor}
          </div>
          <div style={{ marginTop:6, fontSize:'0.7rem', color:'#9ca3af', fontStyle:'italic' }}>
            AI assessment only. Confirm with blood tests. Always consult a licensed healthcare professional.
          </div>
        </div>
      )}
    </div>
  );
}

// ── Chatbot ───────────────────────────────────────────────────────────────────
function Chatbot({ user }) {
  const makeWelcome = () => ({
    id:'w', type:'ai', results:null,
    text:`Hello ${user?.name?.split(' ')[0]||'there'}!\n\nI'm MediHelp AI — your Kenya nutrition health assistant.\n\nDescribe your symptoms in plain language and I'll identify possible nutritional deficiencies with Kenyan food solutions.\n\n**Try:** "I feel tired all the time, my hair is falling out and I get dizzy"\n\nWhat symptoms are you experiencing?`
  });

  const [messages, setMessages] = useState([makeWelcome()]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const endRef = useRef(null);

  useEffect(() => { endRef.current?.scrollIntoView({ behavior:'smooth' }); }, [messages, loading]);

  const send = async () => {
    const text = input.trim();
    if (!text || loading) return;
    setInput('');
    setMessages(m => [...m, { id:Date.now(), type:'user', text, results:null }]);
    setLoading(true);
    await new Promise(r => setTimeout(r, 800));

    const results = analyzeSymptoms(text);
    const reply = results.length > 0
      ? `I found **${results.length} potential deficiency risk${results.length>1?'s':''}** based on your symptoms.\n\nTop match: **${results[0].name}** (${results[0].confidence}% confidence).\n\nExpand each card for Kenyan food remedies, tips, and supplement guidance. Always confirm with a blood test and consult a doctor.`
      : `I couldn't match a specific deficiency from those symptoms. Try adding more detail — for example:\n\n• "I feel **tired**, look **pale** and get **dizzy**" — Iron\n• "**Bone pain**, **back pain** and feel **depressed**" — Vitamin D\n• "**Numbness** in hands and feet, **forgetful**" — B12\n• "Child has **swollen belly** and not growing" — Protein`;

    setMessages(m => [...m, { id:Date.now()+1, type:'ai', text:reply, results }]);
    setLoading(false);
    try { await api.post('/api/analyze', { symptoms:text }); } catch { /* non-critical */ }
  };

  const fmt = t => t.replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>').replace(/\n/g,'<br/>');

  return (
    <div style={{ display:'flex', flexDirection:'column', height:'calc(100vh - 180px)', minHeight:520, borderRadius:14, overflow:'hidden', border:'1px solid #e5e7eb', boxShadow:'0 4px 24px rgba(0,0,0,0.07)' }}>
      {/* Header */}
      <div style={{ padding:'1rem 1.25rem', background:'linear-gradient(135deg,#052e16 0%,#15803d 100%)', color:'white', display:'flex', alignItems:'center', gap:12, flexShrink:0 }}>
        <div style={{ width:40, height:40, borderRadius:'50%', background:'rgba(255,255,255,0.15)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
          <I c="fa-stethoscope" style={{fontSize:'1.1rem'}}/>
        </div>
        <div style={{ flex:1 }}>
          <div style={{ fontWeight:700, fontSize:'0.95rem' }}>MediHelp Nutrition AI</div>
          <div style={{ fontSize:'0.72rem', opacity:0.8, display:'flex', alignItems:'center', gap:6 }}>
            <span style={{ width:6, height:6, background:'#86efac', borderRadius:'50%', display:'inline-block', animation:'chatpulse 2s infinite' }}/>
            Kenya Deficiency Specialist · Runs offline
          </div>
        </div>
        <button onClick={()=>setMessages([makeWelcome()])} style={{ background:'rgba(255,255,255,0.12)', border:'1px solid rgba(255,255,255,0.2)', color:'white', borderRadius:8, padding:'5px 12px', cursor:'pointer', fontSize:'0.78rem', fontFamily:'Outfit,sans-serif', display:'flex', alignItems:'center', gap:5 }}>
          <I c="fa-rotate"/>Clear
        </button>
      </div>

      {/* Messages */}
      <div style={{ flex:1, overflowY:'auto', padding:'1rem', background:'#f4f6fb', display:'flex', flexDirection:'column', gap:12 }}>
        {messages.map(msg => (
          <div key={msg.id} style={{ animation:'msgfade 0.3s ease' }}>
            <div style={{ display:'flex', gap:8, justifyContent:msg.type==='user'?'flex-end':'flex-start', alignItems:'flex-end' }}>
              {msg.type==='ai' && (
                <div style={{ width:28, height:28, borderRadius:'50%', background:'linear-gradient(135deg,#16a34a,#15803d)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, marginBottom:2 }}>
                  <I c="fa-stethoscope" style={{fontSize:'0.7rem', color:'white'}}/>
                </div>
              )}
              <div style={{ maxWidth:'78%', padding:'0.65rem 1rem', borderRadius:msg.type==='user'?'18px 18px 4px 18px':'18px 18px 18px 4px', background:msg.type==='user'?'linear-gradient(135deg,#16a34a,#15803d)':'white', color:msg.type==='user'?'white':'#111827', border:msg.type==='ai'?'1px solid #e5e7eb':'none', fontSize:'0.875rem', lineHeight:1.7, boxShadow:'0 1px 4px rgba(0,0,0,0.06)' }}>
                <span dangerouslySetInnerHTML={{ __html:fmt(msg.text) }}/>
              </div>
              {msg.type==='user' && (
                <div style={{ width:28, height:28, borderRadius:'50%', background:'#374151', display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontSize:'0.72rem', fontWeight:700, flexShrink:0, marginBottom:2 }}>
                  {(user?.name||'U')[0].toUpperCase()}
                </div>
              )}
            </div>
            {msg.results?.length > 0 && (
              <div style={{ marginTop:10, marginLeft:36 }}>
                {msg.results.map(r => <DefCard key={r.id} r={r}/>)}
              </div>
            )}
          </div>
        ))}

        {loading && (
          <div style={{ display:'flex', gap:8, alignItems:'flex-end' }}>
            <div style={{ width:28, height:28, borderRadius:'50%', background:'linear-gradient(135deg,#16a34a,#15803d)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
              <I c="fa-stethoscope" style={{fontSize:'0.7rem', color:'white'}}/>
            </div>
            <div style={{ padding:'0.65rem 1rem', background:'white', border:'1px solid #e5e7eb', borderRadius:'18px 18px 18px 4px', display:'flex', gap:4, alignItems:'center' }}>
              {[0,1,2].map(i => <span key={i} style={{ width:7, height:7, background:'#16a34a', borderRadius:'50%', display:'inline-block', animation:`chatbounce 1.1s ease-in-out ${i*0.18}s infinite` }}/>)}
              <span style={{ marginLeft:8, fontSize:'0.78rem', color:'#6b7280', fontStyle:'italic' }}>Analysing symptoms...</span>
            </div>
          </div>
        )}
        <div ref={endRef}/>
      </div>

      {/* Input */}
      <div style={{ padding:'0.75rem 1rem', background:'white', borderTop:'1px solid #e5e7eb', flexShrink:0 }}>
        <div style={{ display:'flex', gap:8 }}>
          <textarea value={input} onChange={e=>setInput(e.target.value)}
            onKeyDown={e=>{ if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();send();} }}
            placeholder="Describe your symptoms... e.g. I feel tired, my hair is falling out and I get dizzy"
            rows={2} disabled={loading}
            style={{ flex:1, padding:'0.65rem 1rem', border:'1.5px solid #e5e7eb', borderRadius:10, fontFamily:'Outfit,sans-serif', fontSize:'0.875rem', resize:'none', outline:'none', lineHeight:1.5, transition:'border-color 0.18s', color:'#111827' }}
            onFocus={e=>e.target.style.borderColor='#16a34a'}
            onBlur={e=>e.target.style.borderColor='#e5e7eb'}
          />
          <button onClick={send} disabled={!input.trim()||loading} className="btn btn-primary" style={{ borderRadius:10, padding:'0 1.25rem', flexShrink:0, gap:6 }}>
            <I c="fa-paper-plane"/>
          </button>
        </div>
        <div style={{ fontSize:'0.68rem', color:'#9ca3af', marginTop:5 }}>
          Press Enter to send · AI guidance only · Not a substitute for medical advice
        </div>
      </div>

      <style>{`
        @keyframes chatbounce { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-5px)} }
        @keyframes chatpulse  { 0%,100%{opacity:1} 50%{opacity:0.3} }
        @keyframes msgfade    { from{opacity:0;transform:translateY(6px)} to{opacity:1;transform:translateY(0)} }
      `}</style>
    </div>
  );
}

// ── History ───────────────────────────────────────────────────────────────────
function History() {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    api.get('/api/history')
      .then(r => { setHistory(r.data); setLoading(false); })
      .catch(() => { setError('Could not load history. Make sure the backend is running.'); setLoading(false); });
  }, []);

  if (loading) return <div style={{textAlign:'center',padding:'3rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div>;
  if (error)   return <div className="alert alert-warning"><I c="fa-triangle-exclamation" style={{marginRight:8}}/>{error}</div>;
  if (!history.length) return (
    <div style={{textAlign:'center',padding:'3rem',color:'#6b7280'}}>
      <I c="fa-clipboard-list" style={{fontSize:'3rem',marginBottom:12,display:'block',color:'#d1d5db'}}/>
      <p>No analyses saved yet. Chat with the AI to get started!</p>
    </div>
  );

  return (
    <div>
      <h3 style={{fontSize:'1rem',fontFamily:'Outfit,sans-serif',fontWeight:700,marginBottom:'1rem',color:'#374151',display:'flex',alignItems:'center',gap:8}}>
        <I c="fa-clock-rotate-left" style={{color:'#16a34a'}}/>Analysis History ({history.length})
      </h3>
      {history.map(h => (
        <div key={h.id} className="card" style={{marginBottom:10}}>
          <div style={{fontSize:'0.78rem',color:'#6b7280',marginBottom:4,display:'flex',alignItems:'center',gap:5}}>
            <I c="fa-clock"/>{new Date(h.timestamp).toLocaleString('en-KE')}
          </div>
          <div style={{fontSize:'0.875rem',color:'#374151',fontStyle:'italic',marginBottom:8}}>
            "{h.symptoms.length>120 ? h.symptoms.substring(0,120)+'...' : h.symptoms}"
          </div>
          {h.results?.length > 0 ? (
            <div style={{display:'flex',flexWrap:'wrap',gap:6}}>
              {h.results.map(r => (
                <span key={r.id} style={{display:'inline-flex',alignItems:'center',gap:5,background:`${r.color}10`,color:r.color,border:`1px solid ${r.color}30`,borderRadius:20,padding:'4px 12px',fontSize:'0.78rem',fontWeight:600}}>
                  <I c={DEF_ICONS[r.id]||'fa-circle-dot'}/>{r.name} · {r.confidence}%
                </span>
              ))}
            </div>
          ) : (
            <span style={{fontSize:'0.78rem',color:'#9ca3af'}}>No deficiencies matched</span>
          )}
        </div>
      ))}
    </div>
  );
}

// ── Hospital Map ──────────────────────────────────────────────────────────────
function HospitalMap() {
  const [hospitals, setHospitals]   = useState([]);
  const [loading, setLoading]       = useState(true);
  const [error, setError]           = useState('');
  const [search, setSearch]         = useState('');
  const [selected, setSelected]     = useState(null);
  const [userLocation, setUserLocation] = useState(null);
  const [locating, setLocating]     = useState(false);
  const [mapCenter, setMapCenter]   = useState(null);

  const fetchHospitals = useCallback((lat, lon, q) => {
    setLoading(true);
    const params = new URLSearchParams();
    if (lat != null) params.set('lat', lat);
    if (lon != null) params.set('lon', lon);
    if (q) params.set('q', q);
    api.get(`/api/hospitals?${params}`)
      .then(r => { setHospitals(r.data); setLoading(false); })
      .catch(() => { setError('Could not load hospitals. Make sure the backend is running.'); setLoading(false); });
  }, []);

  useEffect(() => { fetchHospitals(null, null, ''); }, [fetchHospitals]);

  const getLocation = () => {
    if (!navigator.geolocation) { alert('Geolocation not supported by your browser.'); return; }
    setLocating(true);
    navigator.geolocation.getCurrentPosition(
      pos => {
        const { latitude: lat, longitude: lon } = pos.coords;
        setUserLocation({ lat, lon });
        setMapCenter([lat, lon]);
        setLocating(false);
        fetchHospitals(lat, lon, search);
      },
      () => { alert('Could not get your location. Please allow location access in your browser.'); setLocating(false); }
    );
  };

  const doSearch = () => {
    fetchHospitals(userLocation?.lat, userLocation?.lon, search);
  };

  const hospitalIcon = L.divIcon({
    html:`<div style="background:#16a34a;width:30px;height:30px;border-radius:50%;border:2.5px solid white;box-shadow:0 2px 8px rgba(0,0,0,0.3);display:flex;align-items:center;justify-content:center;color:white;font-size:13px"><i class='fa-solid fa-hospital-user'></i></div>`,
    className:'', iconSize:[30,30], iconAnchor:[15,15]
  });

  const userIcon = L.divIcon({
    html:`<div style="background:#0891b2;width:28px;height:28px;border-radius:50%;border:2.5px solid white;box-shadow:0 2px 8px rgba(0,0,0,0.3);display:flex;align-items:center;justify-content:center;color:white;font-size:12px"><i class='fa-solid fa-location-crosshairs'></i></div>`,
    className:'', iconSize:[28,28], iconAnchor:[14,14]
  });

  const defaultCenter = userLocation
    ? [userLocation.lat, userLocation.lon]
    : [-1.2921, 36.8219];

  return (
    <div>
      <h3 style={{fontSize:'1rem',fontFamily:'Outfit,sans-serif',fontWeight:700,marginBottom:'1rem',color:'#374151',display:'flex',alignItems:'center',gap:8}}>
        <I c="fa-hospital" style={{color:'#16a34a'}}/>Healthcare Facilities
      </h3>

      {/* Search + Location bar */}
      <div style={{display:'flex',gap:8,marginBottom:'1rem',flexWrap:'wrap'}}>
        <div style={{position:'relative',flex:1,minWidth:200}}>
          <I c="fa-magnifying-glass" style={{position:'absolute',left:10,top:'50%',transform:'translateY(-50%)',color:'#9ca3af',fontSize:'0.85rem'}}/>
          <input className="form-input" value={search} onChange={e=>setSearch(e.target.value)}
            onKeyDown={e=>e.key==='Enter'&&doSearch()}
            placeholder="Search by name, city, type, service..."
            style={{paddingLeft:34}}/>
        </div>
        <button className="btn btn-outline" onClick={doSearch} style={{flexShrink:0}}>
          <I c="fa-magnifying-glass" style={{marginRight:6}}/>Search
        </button>
        <button className="btn btn-primary" onClick={getLocation} disabled={locating} style={{flexShrink:0}}>
          {locating
            ? <><span className="spinner" style={{width:14,height:14}}/> Locating...</>
            : <><I c="fa-location-crosshairs" style={{marginRight:6}}/>Near Me</>}
        </button>
      </div>

      {userLocation && (
        <div className="alert alert-success" style={{marginBottom:'1rem',padding:'8px 12px',fontSize:'0.82rem'}}>
          <I c="fa-circle-check" style={{marginRight:6}}/>
          Showing hospitals sorted by distance from your location. Nearest first.
        </div>
      )}

      {error && <div className="alert alert-warning"><I c="fa-triangle-exclamation" style={{marginRight:8}}/>{error}</div>}

      {/* Map */}
      <div style={{borderRadius:12,overflow:'hidden',border:'1px solid #e5e7eb',marginBottom:'1rem',boxShadow:'0 2px 12px rgba(0,0,0,0.06)'}}>
        <MapContainer center={defaultCenter} zoom={6} style={{height:360}}>
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'/>
          {mapCenter && <FlyTo coords={mapCenter}/>}
          {userLocation && (
            <Marker position={[userLocation.lat, userLocation.lon]} icon={userIcon}>
              <Popup><strong style={{color:'#0891b2'}}>Your Location</strong></Popup>
            </Marker>
          )}
          {hospitals.map(h => (
            <Marker key={h.id} position={[h.latitude, h.longitude]} icon={hospitalIcon}
              eventHandlers={{click:()=>setSelected(h)}}>
              <Popup>
                <strong style={{color:'#16a34a'}}>{h.name}</strong><br/>
                {h.address}<br/>
                <I c="fa-phone" style={{marginRight:4}}/>{h.phone}
                {h.distance_km != null && <><br/><I c="fa-route" style={{marginRight:4}}/>{h.distance_km} km away</>}
                {h.emergency ? <><br/><span style={{color:'#dc2626',fontWeight:700}}><I c="fa-kit-medical" style={{marginRight:4}}/>24hr Emergency</span></> : null}
              </Popup>
            </Marker>
          ))}
        </MapContainer>
      </div>

      {/* Hospital cards */}
      {loading
        ? <div style={{textAlign:'center',padding:'2rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div>
        : hospitals.length === 0
          ? <div style={{textAlign:'center',padding:'2rem',color:'#6b7280'}}>
              <I c="fa-hospital-slash" style={{fontSize:'2rem',marginBottom:8,display:'block',color:'#d1d5db'}}/>
              No hospitals found matching your search.
            </div>
          : (
            <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(280px,1fr))',gap:10}}>
              {hospitals.map(h => {
                let services = [];
                try { services = typeof h.services==='string' ? JSON.parse(h.services||'[]') : (h.services||[]); } catch {}
                return (
                  <div key={h.id} className="card" onClick={()=>setSelected(selected?.id===h.id?null:h)}
                    style={{ cursor:'pointer', border:selected?.id===h.id?'2px solid #16a34a':'1px solid #e5e7eb', padding:'0.9rem', transition:'border 0.15s' }}>
                    <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:6}}>
                      <div style={{fontWeight:700,fontSize:'0.875rem',color:'#111827',flex:1}}>{h.name}</div>
                      <div style={{display:'flex',gap:4,flexShrink:0,marginLeft:8}}>
                        <span style={{background:h.type==='private'?'#dcfce7':'#dbeafe',color:h.type==='private'?'#16a34a':'#1d4ed8',borderRadius:6,padding:'1px 7px',fontSize:'0.65rem',fontWeight:700,textTransform:'capitalize'}}>{h.type}</span>
                        {h.emergency ? <span style={{background:'#fef2f2',color:'#dc2626',borderRadius:6,padding:'1px 6px',fontSize:'0.65rem',fontWeight:700}}>24h</span> : null}
                      </div>
                    </div>
                    <div style={{fontSize:'0.78rem',color:'#6b7280',marginBottom:3,display:'flex',alignItems:'center',gap:5}}>
                      <I c="fa-location-dot" style={{color:'#16a34a',fontSize:'0.7rem'}}/>{h.address}
                    </div>
                    <div style={{fontSize:'0.78rem',color:'#16a34a',fontWeight:600,marginBottom:h.distance_km?6:0,display:'flex',alignItems:'center',gap:5}}>
                      <I c="fa-phone"/>{h.phone}
                    </div>
                    {h.distance_km != null && (
                      <div style={{fontSize:'0.75rem',color:'#0891b2',fontWeight:700,marginBottom:4,display:'flex',alignItems:'center',gap:5}}>
                        <I c="fa-route"/>{h.distance_km} km away
                      </div>
                    )}
                    {services.length > 0 && (
                      <div style={{display:'flex',flexWrap:'wrap',gap:4,marginTop:6}}>
                        {services.slice(0,3).map(s=>(
                          <span key={s} style={{background:'#f0fdf4',color:'#15803d',borderRadius:6,padding:'1px 6px',fontSize:'0.65rem',fontWeight:600}}>{s}</span>
                        ))}
                        {services.length>3&&<span style={{background:'#f3f4f6',color:'#6b7280',borderRadius:6,padding:'1px 6px',fontSize:'0.65rem'}}>+{services.length-3}</span>}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )
      }
    </div>
  );
}

// ── Profile ───────────────────────────────────────────────────────────────────
function Profile() {
  const { user, login, token } = useAuth();
  const [form, setForm] = useState({ name:user?.name||'', age:user?.age||'', blood_group:user?.blood_group||'', allergies:user?.allergies||'', chronic_conditions:user?.chronic_conditions||'' });
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState('');
  const BLOOD_GROUPS = ['A+','A-','B+','B-','AB+','AB-','O+','O-'];
  const set = k => e => setForm({...form,[k]:e.target.value});

  const handleSave = async e => {
    e.preventDefault(); setSaving(true); setMsg('');
    try {
      const res = await api.put('/api/profile', form);
      login(res.data, token);
      setMsg('Profile updated!');
    } catch { setMsg('Failed to save. Is the backend running?'); }
    setSaving(false);
  };

  return (
    <div style={{maxWidth:460}}>
      <h3 style={{fontSize:'1rem',fontFamily:'Outfit,sans-serif',fontWeight:700,marginBottom:'1rem',color:'#374151',display:'flex',alignItems:'center',gap:8}}>
        <I c="fa-user-circle" style={{color:'#16a34a'}}/>My Health Profile
      </h3>
      {msg && <div className={`alert ${msg.includes('updated')?'alert-success':'alert-error'}`}>{msg}</div>}
      <form onSubmit={handleSave} className="card">
        <div className="form-group">
          <label className="form-label"><I c="fa-user" style={{marginRight:6,color:'#6b7280'}}/>Full Name</label>
          <input className="form-input" value={form.name} onChange={set('name')} required/>
        </div>
        <div className="grid-2">
          <div className="form-group">
            <label className="form-label"><I c="fa-calendar" style={{marginRight:6,color:'#6b7280'}}/>Age</label>
            <input type="number" className="form-input" value={form.age} onChange={set('age')} min="1" max="120"/>
          </div>
          <div className="form-group">
            <label className="form-label"><I c="fa-droplet" style={{marginRight:6,color:'#dc2626'}}/>Blood Group</label>
            <select className="form-input" value={form.blood_group} onChange={set('blood_group')}>
              <option value="">Unknown</option>
              {BLOOD_GROUPS.map(b=><option key={b}>{b}</option>)}
            </select>
          </div>
        </div>
        <div className="form-group">
          <label className="form-label"><I c="fa-triangle-exclamation" style={{marginRight:6,color:'#d97706'}}/>Known Allergies</label>
          <input className="form-input" value={form.allergies} onChange={set('allergies')} placeholder="e.g. peanuts, shellfish"/>
        </div>
        <div className="form-group">
          <label className="form-label"><I c="fa-notes-medical" style={{marginRight:6,color:'#0891b2'}}/>Chronic Conditions</label>
          <input className="form-input" value={form.chronic_conditions} onChange={set('chronic_conditions')} placeholder="e.g. diabetes, hypertension"/>
        </div>
        <button type="submit" className="btn btn-primary" disabled={saving} style={{width:'100%',justifyContent:'center',padding:'0.7rem'}}>
          {saving ? <><span className="spinner" style={{width:16,height:16}}/> Saving...</> : <><I c="fa-floppy-disk" style={{marginRight:6}}/>Save Profile</>}
        </button>
      </form>
      <div style={{marginTop:'1rem',padding:'0.9rem',background:'#f0fdf4',borderRadius:10,fontSize:'0.78rem',color:'#6b7280',display:'flex',gap:8,alignItems:'flex-start'}}>
        <I c="fa-lock" style={{color:'#16a34a',marginTop:2,flexShrink:0}}/>
        Your data is stored locally and encrypted in transit. It is never sold to third parties.
      </div>
    </div>
  );
}

// ── Dashboard Shell ───────────────────────────────────────────────────────────
const TABS = [
  { key:'chat',      icon:'fa-stethoscope', label:'AI Chat'   },
  { key:'history',   icon:'fa-clock-rotate-left', label:'History'  },
  { key:'hospitals', icon:'fa-hospital',    label:'Hospitals' },
  { key:'profile',   icon:'fa-user',        label:'Profile'   },
];

export default function Dashboard() {
  const { user } = useAuth();
  const [tab, setTab] = useState('chat');

  return (
    <div style={{maxWidth:1100,margin:'0 auto',padding:'1.5rem 1.25rem'}}>
      <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:'1.25rem',flexWrap:'wrap',gap:8}}>
        <div>
          <h2 style={{fontSize:'1.4rem',marginBottom:2,display:'flex',alignItems:'center',gap:8}}>
            <I c="fa-hand-wave" style={{color:'#d97706'}}/>Hello, {user?.name?.split(' ')[0]}
          </h2>
          <p style={{color:'#6b7280',fontSize:'0.875rem'}}>MediHelp AI Nutrition Dashboard</p>
        </div>
        <div style={{display:'flex',gap:6,flexWrap:'wrap'}}>
          {user?.blood_group && (
            <span style={{background:'#fef2f2',color:'#dc2626',border:'1px solid #fca5a5',borderRadius:8,padding:'4px 10px',fontSize:'0.75rem',fontWeight:700,display:'flex',alignItems:'center',gap:5}}>
              <I c="fa-droplet"/>{user.blood_group}
            </span>
          )}
          {user?.allergies && (
            <span style={{background:'#fffbeb',color:'#d97706',border:'1px solid #fcd34d',borderRadius:8,padding:'4px 10px',fontSize:'0.75rem',fontWeight:600,display:'flex',alignItems:'center',gap:5}}>
              <I c="fa-triangle-exclamation"/>{user.allergies}
            </span>
          )}
        </div>
      </div>

      <div className="tabs">
        {TABS.map(t => (
          <button key={t.key} className={`tab ${tab===t.key?'active':''}`} onClick={()=>setTab(t.key)}>
            <I c={t.icon} style={{marginRight:6}}/>{t.label}
          </button>
        ))}
      </div>

      {tab==='chat'      && <Chatbot user={user}/>}
      {tab==='history'   && <History/>}
      {tab==='hospitals' && <HospitalMap/>}
      {tab==='profile'   && <Profile/>}
    </div>
  );
}
